137	uint64_t Object::SizeOf() {
138	    if (IsArrayInstance()) {
139	        Array array = *this;
140	        return array.SizeOf();
141	    } else if (IsClass()) {
142	        Class clazz = *this;
143	        return clazz.SizeOf();
144	    } else if (IsString()) {
145	        String value = *this;
146	        return value.SizeOf();
147	    } else {
148	        return GetClass().GetObjectSize();
149	    }
150	    return 0x0;
151	}
