161	bool Object::IsValid() {
162	    try {
163	        Class klass_ = GetClass();
164	        if (klass_.Ptr() == 0x0 || klass_.Ptr() == kPoisonDeadObject)
165	            return false;
166	
167	        if (LIKELY(klass_.IsClass())
168	                && LIKELY(!((int64_t)SizeOf() < (int64_t)kObjectAlignment)))
169	            return true;
170	    } catch (InvalidAddressException& e) {
171	        // do nothing
172	    }
173	    return false;
174	}
175	
176	bool Object::IsNonLargeValid() {
177	    try {
178	        Class klass_ = GetClass();
179	        if (klass_.Ptr() == 0x0 || klass_.Ptr() == kPoisonDeadObject)
180	            return false;
181	
182	        if (LIKELY(klass_.IsClass())) {
183	            int64_t thiz_size = SizeOf();
184	            if (LIKELY(!(thiz_size < (int64_t)kObjectAlignment))
185	                    && LIKELY(thiz_size < kValidObjectSize /** 1MB*/)) {
186	                return true;
187	            } else {
188	                if (LIKELY(!(thiz_size < kValidObjectSize)))
189	                    LOGD("This bad object (%" PRIx64 ") too large.\n", Ptr());
190	                if (LIKELY(!!(thiz_size < (int64_t)kObjectAlignment)))
191	                    LOGD("This bad object (%" PRIx64 ") too small.\n", Ptr());
192	                return false;
193	            }
194	        }
195	    } catch (InvalidAddressException& e) {
196	        // do nothing
197	    }
198	    return false;
199	}
