201	uint64_t Object::NextValidOffset(uint64_t max) {
202	    Object thiz = Ptr();
203	    do {
204	        thiz = thiz.Ptr() + kObjectAlignment;
205	        thiz.copyRef(this);
206	        if (thiz.IsValid())
207	            break;
208	    } while (thiz.Ptr() < max);
209	    return thiz.Ptr();
210	}
